import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [list, setList] = useState([]);
  const [form, setForm] = useState({ name: '', skill: '', price: '', email: '' });

  // Backend kadun data aanne
  useEffect(() => {
    fetch('http://localhost:5000/api/get')
      .then(res => res.json())
      .then(data => setList(data))
      .catch(err => console.log("Fetch Error:", err));
  }, []);

  // Form submit karnyacha function
  const handleAdd = async (e) => {
    e.preventDefault();
    const res = await fetch('http://localhost:5000/api/add', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    if (res.ok) {
      alert("Freelancer Registered Successfully!");
      window.location.reload(); // Refresh karnyasathi
    }
  };

  return (
    <div className="container">
      <header><h1>Freelance Marketplace Hub</h1></header>
      
      <div className="main">
        {/* Registration Section */}
        <div className="card-form">
          <h2>Add Your Skill</h2>
          <form onSubmit={handleAdd}>
            <input type="text" placeholder="Full Name" required onChange={e => setForm({...form, name: e.target.value})} />
            <input type="text" placeholder="Skill (e.g. Web Dev)" required onChange={e => setForm({...form, skill: e.target.value})} />
            <input type="number" placeholder="Price Per Hour ($)" required onChange={e => setForm({...form, price: e.target.value})} />
            <input type="email" placeholder="Email Address" required onChange={e => setForm({...form, email: e.target.value})} />
            <button type="submit">Join Marketplace</button>
          </form>
        </div>

        {/* Display List Section */}
        <div className="list">
          <h2>Hire Top Freelancers</h2>
          <div className="grid">
            {list.length > 0 ? list.map(f => (
              <div className="user-card" key={f._id}>
                <h3>{f.name}</h3>
                <p><b>Expertise:</b> {f.skill}</p>
                <p><b>Rate:</b> ${f.price}/hr</p>
                <small>Contact: {f.email}</small>
              </div>
            )) : <p>Loading freelancers...</p>}
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
